import os
import boto3
from botocore.exceptions import NoCredentialsError, PartialCredentialsError

def load_latest_model(model_bucket, model_prefix):
    s3 = boto3.client('s3')
    
    try:
        # List objects in the bucket with the given prefix
        response = s3.list_objects_v2(Bucket=model_bucket, Prefix=model_prefix)
        
        if 'Contents' not in response:
            raise ValueError("No models found in the specified path.")
        
        # Sort objects by last modified time and get the latest one
        latest_model = max(response['Contents'], key=lambda x: x['LastModified'])
        model_key = latest_model['Key']
        
        # Download the latest model to a local file
        local_model_path = '/tmp/latest_model.pkl'
        s3.download_file(model_bucket, model_key, local_model_path)
        
        return local_model_path
    
    except (NoCredentialsError, PartialCredentialsError) as e:
        raise Exception("AWS credentials not found or incomplete.") from e
    except Exception as e:
        raise Exception(f"Failed to load the latest model: {e}")

def main():
    # Get the model path from environment variable
    model_path_env = os.getenv('MODEL_PATH')
    
    if not model_path_env:
        raise ValueError("Environment variable MODEL_PATH is not set.")
    
    # Split the environment variable into bucket and prefix
    parts = model_path_env.split('/', 3)
    if len(parts) != 4 or parts[0] != '' or parts[1] != '':
        raise ValueError("Invalid format for MODEL_PATH. Expected: s3://bucket/prefix")
    
    model_bucket = parts[2]
    model_prefix = parts[3]
    
    # Load the latest model
    local_model_path = load_latest_model(model_bucket, model_prefix)
    
    print(f"Latest model loaded from {local_model_path}")

if __name__ == "__main__":
    main()